<?php namespace App\Models; use Illuminate\Database\Eloquent\Model; class Tournament extends Model { protected $casts=['bracket'=>'array']; protected $fillable=['creator_id','game_id','stages','seats_per_match','entry_fee','prize_pool','status','bracket']; public function creator(){return $this->belongsTo(User::class,'creator_id');} public function game(){return $this->belongsTo(Game::class);} public function entries(){return $this->hasMany(TournamentEntry::class);}  }
